import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        String safeUserInput = encodeForHtml(userInput);

        String htmlResponse = "<html><body>User input: " + safeUserInput + "</body></html>";

        response.getWriter().write(htmlResponse);
    }

    private String encodeForHtml(String input) {
        // Replace characters that have special meaning in HTML with their corresponding HTML entities
        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
